import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

internal class IndentationRuleSafeAccessExpressionTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a chained call with a safe access followed by a lambda then it should not report indentation violations`() {
        val code =
            """
            private fun test(): Boolean? =
                runCatching { true }
                    .getOrNull()?.let { result ->
                        !result
                    }
            """.trimIndent()

        indentationRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

